package com.vasu.conference_management.config;

import com.vasu.conference_management.entity.*;
import com.vasu.conference_management.repository.*;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.time.LocalDateTime;
import java.util.Set;

@Configuration
public class DataInitializer {

    @Bean
    CommandLineRunner seedData(RoleRepository roleRepository,
                               UserRepository userRepository,
                               UserProfileRepository userProfileRepository,
                               ConferenceRepository conferenceRepository,
                               TagRepository tagRepository,
                               PaperRepository paperRepository) {
        return args -> {
            if (roleRepository.count() > 0) {
                return;
            }

            Role adminRole = roleRepository.save(new Role(null, "ADMIN", "Conference chair/admin"));
            Role authorRole = roleRepository.save(new Role(null, "AUTHOR", "Paper author"));
            Role reviewerRole = roleRepository.save(new Role(null, "REVIEWER", "Paper reviewer"));

            User admin = new User();
            admin.setUsername("admin");
            admin.setEmail("admin@conference.local");
            admin.setPassword("admin123");
            admin.setFirstName("System");
            admin.setLastName("Admin");
            admin.setRoles(Set.of(adminRole));
            admin = userRepository.save(admin);

            User author = new User();
            author.setUsername("author1");
            author.setEmail("author1@conference.local");
            author.setPassword("author123");
            author.setFirstName("Alice");
            author.setLastName("Author");
            author.setRoles(Set.of(authorRole));
            author = userRepository.save(author);

            User reviewer = new User();
            reviewer.setUsername("reviewer1");
            reviewer.setEmail("reviewer1@conference.local");
            reviewer.setPassword("review123");
            reviewer.setFirstName("Bob");
            reviewer.setLastName("Reviewer");
            reviewer.setRoles(Set.of(reviewerRole));
            reviewer = userRepository.save(reviewer);

            userProfileRepository.save(new UserProfile(null, "Program chair", "University A", null, null, "Software engineering", admin));
            userProfileRepository.save(new UserProfile(null, "Researcher in AI", "University B", null, null, "Machine learning", author));
            userProfileRepository.save(new UserProfile(null, "Senior reviewer", "Institute C", null, null, "Distributed systems", reviewer));

            Conference conference = new Conference();
            conference.setTitle("International Conference on Software Engineering 2026");
            conference.setDescription("Sample seeded conference");
            conference.setStartDate(LocalDateTime.now().plusMonths(3));
            conference.setEndDate(LocalDateTime.now().plusMonths(3).plusDays(3));
            conference.setSubmissionDeadline(LocalDateTime.now().plusMonths(1));
            conference.setNotificationDate(LocalDateTime.now().plusMonths(2));
            conference.setLocation("Berlin");
            conference.setStatus(Conference.ConferenceStatus.OPEN);
            conference = conferenceRepository.save(conference);

            Tag ai = tagRepository.save(new Tag(null, "AI", "Artificial Intelligence"));
            Tag systems = tagRepository.save(new Tag(null, "Systems", "Computer Systems"));

            Paper paper = new Paper();
            paper.setTitle("A Practical Approach to Conference Management Systems");
            paper.setAbstractText("This is a sample seeded paper.");
            paper.setFilePath("/uploads/sample-paper.pdf");
            paper.setKeywords("conference management, spring boot");
            paper.setConference(conference);
            paper.setAuthor(author);
            paper.setTags(Set.of(ai, systems));
            paper.setReviewers(Set.of(reviewer));
            paper.setStatus(Paper.PaperStatus.UNDER_REVIEW);
            paper.setDecision("PENDING");
            paperRepository.save(paper);
        };
    }
}

package com.vasu.conference_management.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/**", "/error").permitAll()
                        .anyRequest().permitAll()
                )
                .httpBasic(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}

package com.vasu.conference_management.controller;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.Map;

@RestControllerAdvice
public class ApiExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<Map<String, String>> handleIllegalArgument(IllegalArgumentException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(Map.of("error", ex.getMessage()));
    }

    @ExceptionHandler(IllegalStateException.class)
    public ResponseEntity<Map<String, String>> handleIllegalState(IllegalStateException ex) {
        return ResponseEntity.status(HttpStatus.CONFLICT)
                .body(Map.of("error", ex.getMessage()));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, String>> handleValidation(MethodArgumentNotValidException ex) {
        String message = ex.getBindingResult().getFieldErrors().stream()
                .findFirst()
                .map(error -> error.getField() + " " + error.getDefaultMessage())
                .orElse("Validation failed");

        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(Map.of("error", message));
    }
}

package com.vasu.conference_management.controller;

import com.vasu.conference_management.dto.CreateConferenceRequest;
import com.vasu.conference_management.entity.Conference;
import com.vasu.conference_management.service.ConferenceService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/conferences")
public class ConferenceController {
    private final ConferenceService conferenceService;

    public ConferenceController(ConferenceService conferenceService) {
        this.conferenceService = conferenceService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public Map<String, Object> create(@Valid @RequestBody CreateConferenceRequest request) {
        return toResponse(conferenceService.createConference(request));
    }

    @GetMapping
    public List<Map<String, Object>> list() {
        return conferenceService.findAll().stream().map(this::toResponse).toList();
    }

    @GetMapping("/{id}")
    public Map<String, Object> getById(@PathVariable Long id) {
        return toResponse(conferenceService.findById(id));
    }

    private Map<String, Object> toResponse(Conference conference) {
        return Map.of(
                "id", conference.getId(),
                "title", conference.getTitle(),
                "description", conference.getDescription() == null ? "" : conference.getDescription(),
                "startDate", conference.getStartDate(),
                "endDate", conference.getEndDate(),
                "submissionDeadline", conference.getSubmissionDeadline(),
                "status", conference.getStatus(),
                "location", conference.getLocation() == null ? "" : conference.getLocation()
        );
    }
}

package com.vasu.conference_management.controller;

import com.vasu.conference_management.dto.AssignReviewerRequest;
import com.vasu.conference_management.dto.SubmitPaperRequest;
import com.vasu.conference_management.entity.Paper;
import com.vasu.conference_management.service.PaperService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/papers")
public class PaperController {
    private final PaperService paperService;

    public PaperController(PaperService paperService) {
        this.paperService = paperService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public Map<String, Object> submit(@Valid @RequestBody SubmitPaperRequest request) {
        return toResponse(paperService.submitPaper(request));
    }

    @PostMapping("/assign-reviewer")
    public Map<String, Object> assignReviewer(@Valid @RequestBody AssignReviewerRequest request) {
        return toResponse(paperService.assignReviewer(request));
    }

    @PatchMapping("/{paperId}/decision")
    public Map<String, Object> updateDecision(@PathVariable Long paperId, @RequestParam Paper.PaperStatus status) {
        return toResponse(paperService.updateDecision(paperId, status));
    }

    @GetMapping
    public List<Map<String, Object>> listAll(@RequestParam(required = false) Long conferenceId,
                                             @RequestParam(required = false) Paper.PaperStatus status) {
        List<Paper> papers;
        if (conferenceId != null) {
            papers = paperService.findByConference(conferenceId);
        } else if (status != null) {
            papers = paperService.findByStatus(status);
        } else {
            papers = paperService.findAll();
        }
        return papers.stream().map(this::toResponse).toList();
    }

    private Map<String, Object> toResponse(Paper paper) {
        return Map.of(
                "id", paper.getId(),
                "title", paper.getTitle(),
                "status", paper.getStatus(),
                "decision", paper.getDecision() == null ? "PENDING" : paper.getDecision(),
                "conferenceId", paper.getConference().getId(),
                "conferenceTitle", paper.getConference().getTitle(),
                "authorId", paper.getAuthor().getId(),
                "authorUsername", paper.getAuthor().getUsername(),
                "submissionDate", paper.getSubmissionDate(),
                "tags", paper.getTags().stream().map(tag -> tag.getTagName()).toList(),
                "reviewerIds", paper.getReviewers().stream().map(reviewer -> reviewer.getId()).toList()
        );
    }
}

package com.vasu.conference_management.controller;

import com.vasu.conference_management.dto.SubmitReviewRequest;
import com.vasu.conference_management.entity.Review;
import com.vasu.conference_management.service.ReviewService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/reviews")
public class ReviewController {
    private final ReviewService reviewService;

    public ReviewController(ReviewService reviewService) {
        this.reviewService = reviewService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public Map<String, Object> submit(@Valid @RequestBody SubmitReviewRequest request) {
        return toResponse(reviewService.submitReview(request));
    }

    @GetMapping
    public List<Map<String, Object>> byPaper(@RequestParam Long paperId) {
        return reviewService.findByPaper(paperId).stream().map(this::toResponse).toList();
    }

    @GetMapping("/average")
    public Map<String, Object> average(@RequestParam Long paperId) {
        Double average = reviewService.averageScore(paperId);
        return Map.of(
                "paperId", paperId,
                "averageScore", average == null ? 0.0 : average
        );
    }

    private Map<String, Object> toResponse(Review review) {
        return Map.of(
                "id", review.getId(),
                "paperId", review.getPaper().getId(),
                "reviewerId", review.getReviewer().getId(),
                "score", review.getScore(),
                "comments", review.getComments(),
                "recommendation", review.getRecommendation() == null ? "" : review.getRecommendation(),
                "confidenceLevel", review.getConfidenceLevel() == null ? 0 : review.getConfidenceLevel(),
                "reviewDate", review.getReviewDate()
        );
    }
}

package com.vasu.conference_management.dto;

import jakarta.validation.constraints.NotNull;

public class AssignReviewerRequest {
    @NotNull
