    public Long getPaperId() { return paperId; }
    public void setPaperId(Long paperId) { this.paperId = paperId; }
    public Long getReviewerId() { return reviewerId; }
    public void setReviewerId(Long reviewerId) { this.reviewerId = reviewerId; }
}

package com.vasu.conference_management.dto;

import jakarta.validation.constraints.Future;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;

import java.time.LocalDateTime;

public class CreateConferenceRequest {
    @NotBlank
    private String title;
    private String description;
    @NotNull
    @Future
    private LocalDateTime startDate;
    @NotNull
    @Future
    private LocalDateTime endDate;
    @NotNull
    @Future
    private LocalDateTime submissionDeadline;
    private LocalDateTime notificationDate;
    private String location;

    public String getTitle() { return title; }
    public void setTitle(String title) { this.title = title; }
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }
    public LocalDateTime getStartDate() { return startDate; }
    public void setStartDate(LocalDateTime startDate) { this.startDate = startDate; }
    public LocalDateTime getEndDate() { return endDate; }
    public void setEndDate(LocalDateTime endDate) { this.endDate = endDate; }
    public LocalDateTime getSubmissionDeadline() { return submissionDeadline; }
    public void setSubmissionDeadline(LocalDateTime submissionDeadline) { this.submissionDeadline = submissionDeadline; }
    public LocalDateTime getNotificationDate() { return notificationDate; }
    public void setNotificationDate(LocalDateTime notificationDate) { this.notificationDate = notificationDate; }
    public String getLocation() { return location; }
    public void setLocation(String location) { this.location = location; }
}

package com.vasu.conference_management.dto;

import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotEmpty;
import jakarta.validation.constraints.NotNull;

import java.util.Set;

public class SubmitPaperRequest {
    @NotBlank
    private String title;
    @NotBlank
    private String abstractText;
    private String filePath;
    private String keywords;
    @NotNull
    private Long conferenceId;
    @NotNull
    private Long authorId;
    @NotEmpty
    private Set<Long> tagIds;

    public String getTitle() { return title; }
    public void setTitle(String title) { this.title = title; }
    public String getAbstractText() { return abstractText; }
    public void setAbstractText(String abstractText) { this.abstractText = abstractText; }
    public String getFilePath() { return filePath; }
    public void setFilePath(String filePath) { this.filePath = filePath; }
    public String getKeywords() { return keywords; }
    public void setKeywords(String keywords) { this.keywords = keywords; }
    public Long getConferenceId() { return conferenceId; }
    public void setConferenceId(Long conferenceId) { this.conferenceId = conferenceId; }
    public Long getAuthorId() { return authorId; }
    public void setAuthorId(Long authorId) { this.authorId = authorId; }
    public Set<Long> getTagIds() { return tagIds; }
    public void setTagIds(Set<Long> tagIds) { this.tagIds = tagIds; }
}

package com.vasu.conference_management.dto;

import jakarta.validation.constraints.Max;
import jakarta.validation.constraints.Min;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;

public class SubmitReviewRequest {
    @NotNull
    private Long paperId;
    @NotNull
    private Long reviewerId;
    @NotNull
    @Min(1)
    @Max(10)
    private Integer score;
    @NotBlank
    private String comments;
    @NotBlank
    private String recommendation;
    @Min(1)
    @Max(5)
    private Integer confidenceLevel;

    public Long getPaperId() { return paperId; }
    public void setPaperId(Long paperId) { this.paperId = paperId; }
    public Long getReviewerId() { return reviewerId; }
    public void setReviewerId(Long reviewerId) { this.reviewerId = reviewerId; }
    public Integer getScore() { return score; }
    public void setScore(Integer score) { this.score = score; }
    public String getComments() { return comments; }
    public void setComments(String comments) { this.comments = comments; }
    public String getRecommendation() { return recommendation; }
    public void setRecommendation(String recommendation) { this.recommendation = recommendation; }
    public Integer getConfidenceLevel() { return confidenceLevel; }
    public void setConfidenceLevel(Integer confidenceLevel) { this.confidenceLevel = confidenceLevel; }
}

package com.vasu.conference_management.service;

import com.vasu.conference_management.dto.CreateConferenceRequest;
import com.vasu.conference_management.entity.Conference;
import com.vasu.conference_management.repository.ConferenceRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class ConferenceService {
    private final ConferenceRepository conferenceRepository;

    public ConferenceService(ConferenceRepository conferenceRepository) {
        this.conferenceRepository = conferenceRepository;
    }

    @Transactional
    public Conference createConference(CreateConferenceRequest request) {
        Conference conference = new Conference();
        conference.setTitle(request.getTitle());
        conference.setDescription(request.getDescription());
        conference.setStartDate(request.getStartDate());
        conference.setEndDate(request.getEndDate());
        conference.setSubmissionDeadline(request.getSubmissionDeadline());
        conference.setNotificationDate(request.getNotificationDate());
        conference.setLocation(request.getLocation());
        conference.setStatus(Conference.ConferenceStatus.OPEN);
        return conferenceRepository.save(conference);
    }

    @Transactional(readOnly = true)
    public List<Conference> findAll() {
        return conferenceRepository.findAll();
    }

    @Transactional(readOnly = true)
    public Conference findById(Long id) {
        return conferenceRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("Conference not found: " + id));
    }
}

package com.vasu.conference_management.service;

import com.vasu.conference_management.dto.AssignReviewerRequest;
import com.vasu.conference_management.dto.SubmitPaperRequest;
import com.vasu.conference_management.entity.Paper;
import com.vasu.conference_management.entity.Tag;
import com.vasu.conference_management.entity.User;
import com.vasu.conference_management.repository.ConferenceRepository;
import com.vasu.conference_management.repository.PaperRepository;
import com.vasu.conference_management.repository.TagRepository;
import com.vasu.conference_management.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

@Service
public class PaperService {
    private final PaperRepository paperRepository;
    private final ConferenceRepository conferenceRepository;
    private final UserRepository userRepository;
    private final TagRepository tagRepository;

    public PaperService(PaperRepository paperRepository,
                        ConferenceRepository conferenceRepository,
                        UserRepository userRepository,
                        TagRepository tagRepository) {
        this.paperRepository = paperRepository;
        this.conferenceRepository = conferenceRepository;
        this.userRepository = userRepository;
        this.tagRepository = tagRepository;
    }

    @Transactional
    public Paper submitPaper(SubmitPaperRequest request) {
        Paper paper = new Paper();
        paper.setTitle(request.getTitle());
        paper.setAbstractText(request.getAbstractText());
        paper.setFilePath(request.getFilePath());
        paper.setKeywords(request.getKeywords());
        paper.setStatus(Paper.PaperStatus.SUBMITTED);
        paper.setDecision("PENDING");

        paper.setConference(conferenceRepository.findById(request.getConferenceId())
                .orElseThrow(() -> new IllegalArgumentException("Conference not found: " + request.getConferenceId())));

        paper.setAuthor(userRepository.findById(request.getAuthorId())
                .orElseThrow(() -> new IllegalArgumentException("Author not found: " + request.getAuthorId())));

        Set<Tag> tags = new HashSet<>(tagRepository.findAllById(request.getTagIds()));
        if (tags.isEmpty()) {
            throw new IllegalArgumentException("At least one valid tag is required");
        }
        paper.setTags(tags);

        return paperRepository.save(paper);
    }

    @Transactional
    public Paper assignReviewer(AssignReviewerRequest request) {
        Paper paper = paperRepository.findById(request.getPaperId())
                .orElseThrow(() -> new IllegalArgumentException("Paper not found: " + request.getPaperId()));

        User reviewer = userRepository.findById(request.getReviewerId())
                .orElseThrow(() -> new IllegalArgumentException("Reviewer not found: " + request.getReviewerId()));

        paper.getReviewers().add(reviewer);
        paper.setStatus(Paper.PaperStatus.UNDER_REVIEW);
        return paperRepository.save(paper);
    }

    @Transactional
    public Paper updateDecision(Long paperId, Paper.PaperStatus status) {
        if (status != Paper.PaperStatus.ACCEPTED && status != Paper.PaperStatus.REJECTED) {
            throw new IllegalArgumentException("Decision status must be ACCEPTED or REJECTED");
        }

        Paper paper = paperRepository.findById(paperId)
                .orElseThrow(() -> new IllegalArgumentException("Paper not found: " + paperId));

        paper.setStatus(status);
        paper.setDecision(status.name());
        return paperRepository.save(paper);
    }

    @Transactional(readOnly = true)
    public List<Paper> findAll() {
        return paperRepository.findAll();
    }

    @Transactional(readOnly = true)
    public List<Paper> findByConference(Long conferenceId) {
        var conference = conferenceRepository.findById(conferenceId)
                .orElseThrow(() -> new IllegalArgumentException("Conference not found: " + conferenceId));
        return paperRepository.findByConference(conference);
    }

    @Transactional(readOnly = true)
    public List<Paper> findByStatus(Paper.PaperStatus status) {
        return paperRepository.findByStatus(status);
    }
}

package com.vasu.conference_management.service;

import com.vasu.conference_management.dto.SubmitReviewRequest;
import com.vasu.conference_management.entity.Paper;
import com.vasu.conference_management.entity.Review;
import com.vasu.conference_management.entity.User;
import com.vasu.conference_management.repository.PaperRepository;
import com.vasu.conference_management.repository.ReviewRepository;
import com.vasu.conference_management.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class ReviewService {
    private final ReviewRepository reviewRepository;
    private final PaperRepository paperRepository;
    private final UserRepository userRepository;

    public ReviewService(ReviewRepository reviewRepository,
                         PaperRepository paperRepository,
                         UserRepository userRepository) {
        this.reviewRepository = reviewRepository;
        this.paperRepository = paperRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public Review submitReview(SubmitReviewRequest request) {
        Paper paper = paperRepository.findById(request.getPaperId())
                .orElseThrow(() -> new IllegalArgumentException("Paper not found: " + request.getPaperId()));

        User reviewer = userRepository.findById(request.getReviewerId())
                .orElseThrow(() -> new IllegalArgumentException("Reviewer not found: " + request.getReviewerId()));

        boolean assigned = paper.getReviewers().stream().anyMatch(r -> r.getId().equals(reviewer.getId()));
        if (!assigned) {
            throw new IllegalStateException("Reviewer is not assigned to this paper");
        }

        reviewRepository.findByPaperAndReviewer(paper, reviewer)
                .ifPresent(existing -> {
                    throw new IllegalStateException("Reviewer has already submitted a review for this paper");
                });

        Review review = new Review();
        review.setPaper(paper);
        review.setReviewer(reviewer);
        review.setScore(request.getScore());
        review.setComments(request.getComments());
        review.setRecommendation(request.getRecommendation());
        review.setConfidenceLevel(request.getConfidenceLevel());

        return reviewRepository.save(review);
    }

    @Transactional(readOnly = true)
    public List<Review> findByPaper(Long paperId) {
        Paper paper = paperRepository.findById(paperId)
                .orElseThrow(() -> new IllegalArgumentException("Paper not found: " + paperId));
        return reviewRepository.findByPaper(paper);
    }

    @Transactional(readOnly = true)
    public Double averageScore(Long paperId) {
        Paper paper = paperRepository.findById(paperId)
                .orElseThrow(() -> new IllegalArgumentException("Paper not found: " + paperId));
        return reviewRepository.findAverageScoreByPaper(paper);
    }
}
